import sys
from typing import List

def solve(nums: List[int], queries: List[List[int]]) -> List[int]:
    # Precompute popcount-depth for numbers up to 1e15
    max_num = 10**15
    depth_memo = {}

    def get_popcount(x: int) -> int:
        return bin(x).count('1')

    def compute_depth(x: int) -> int:
        if x == 1:
            return 0
        if x in depth_memo:
            return depth_memo[x]
        next_p = get_popcount(x)
        depth = 1 + compute_depth(next_p)
        depth_memo[x] = depth
        return depth

    # Precompute depths for all nums initially
    depths = [0] * len(nums)
    for i in range(len(nums)):
        depths[i] = compute_depth(nums[i])

    answer = []
    for query in queries:
        if query[0] == 1:
            _, l, r, k = query
            count = 0
            for j in range(l, r + 1):
                if depths[j] == k:
                    count += 1
            answer.append(count)
        elif query[0] == 2:
            _, idx, val = query
            nums[idx] = val
            depths[idx] = compute_depth(val)

    return answer
