public class Solution {
    private static HashMap<Long, Integer> depthMemo = new HashMap<>();

    private static int getPopcount(long x) {
        return Long.bitCount(x);
    }

    private static int computeDepth(long x) {
        if (x == 1) {
            return 0;
        }
        if (depthMemo.containsKey(x)) {
            return depthMemo.get(x);
        }
        int nextP = getPopcount(x);
        int depth = 1 + computeDepth(nextP);
        depthMemo.put(x, depth);
        return depth;
    }

    public static long[] solve(long[] nums, long[][] queries) {
        int n = nums.length;
        int[] depths = new int[n];
        for (int i = 0; i < n; i++) {
            depths[i] = computeDepth(nums[i]);
        }

        int answerCount = 0;
        for (long[] query : queries) {
            if (query[0] == 1) {
                answerCount++;
            }
        }

        long[] answer = new long[answerCount];
        int answerIdx = 0;
        for (long[] query : queries) {
            if (query[0] == 1) {
                int l = (int) query[1];
                int r = (int) query[2];
                int k = (int) query[3];
                long count = 0;
                for (int j = l; j <= r; j++) {
                    if (depths[j] == k) {
                        count++;
                    }
                }
                answer[answerIdx++] = count;
            } else if (query[0] == 2) {
                int idx = (int) query[1];
                long val = query[2];
                nums[idx] = val;
                depths[idx] = computeDepth(val);
            }
        }
        return answer;
    }
}
